#' Leave-One-Center-Out Cross-Validation
#'
#' Performs leave-one-center-out cross-validation for multi-institutional
#' prediction models. Trains on all-but-one center and evaluates on the
#' held-out center, repeating for each center. Provides internal-external
#' validation recommended by TRIPOD and Debray et al. (2015).
#' 
#'
#' @examples
#' \donttest{
#' leaveonecenterout(data = data, outcome = "diagnosis",
#'     outcomeLevel = "PanNEC", predictors = vars(p53, Rb1, SSTR2A),
#'     centerVariable = "institution", modelType = "logistic")
#'}
#' @param data The data as a data frame.
#' @param outcome Outcome variable to predict. Binary for logistic, continuous
#'   for linear.
#' @param outcomeLevel Level of outcome considered as the event (for binary
#'   outcomes).
#' @param predictors Variables to include in the prediction model.
#' @param centerVariable Grouping variable identifying center, institution, or
#'   study site. Each unique level is used as a held-out test set in turn.
#'   Minimum 3 centers required.
#' @param elapsedtime Survival time variable. Only required when modelType is
#'   cox.
#' @param modelType Type of prediction model to fit in each fold.
#' @param useLasso Apply LASSO (L1) penalty for automatic variable selection
#'   within each CV fold. Recommended when number of predictors is large.
#' @param lambdaMethod Lambda selection method for LASSO (inner CV within each
#'   training fold).
#' @param random_seed Random seed for reproducibility.
#' @param pooledPerformance Show pooled (average) performance across all
#'   held-out centers.
#' @param forestPlot Show forest plot of AUC/C-index per center with pooled
#'   estimate.
#' @param calibrationCheck Assess calibration (Brier score) per center and
#'   pooled.
#' @return A results object containing:
#' \tabular{llllll}{
#'   \code{results$todo} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$designSummary} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$perCenterResults} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$pooledPerformance} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$forestplot} \tab \tab \tab \tab \tab an image \cr
#'   \code{results$interpretation} \tab \tab \tab \tab \tab a html \cr
#' }
#'
#' Tables can be converted to data frames with \code{asDF} or \code{\link{as.data.frame}}. For example:
#'
#' \code{results$designSummary$asDF}
#'
#' \code{as.data.frame(results$designSummary)}
#'
#' @export
leaveonecenterout <- function(
    data,
    outcome,
    outcomeLevel,
    predictors,
    centerVariable,
    elapsedtime = NULL,
    modelType = "logistic",
    useLasso = FALSE,
    lambdaMethod = "lambda.1se",
    random_seed = 42,
    pooledPerformance = TRUE,
    forestPlot = TRUE,
    calibrationCheck = FALSE) {

    if ( ! requireNamespace("jmvcore", quietly=TRUE))
        stop("leaveonecenterout requires jmvcore to be installed (restart may be required)")

    if ( ! missing(outcome)) outcome <- jmvcore::resolveQuo(jmvcore::enquo(outcome))
    if ( ! missing(predictors)) predictors <- jmvcore::resolveQuo(jmvcore::enquo(predictors))
    if ( ! missing(centerVariable)) centerVariable <- jmvcore::resolveQuo(jmvcore::enquo(centerVariable))
    if ( ! missing(elapsedtime)) elapsedtime <- jmvcore::resolveQuo(jmvcore::enquo(elapsedtime))
    if (missing(data))
        data <- jmvcore::marshalData(
            parent.frame(),
            `if`( ! missing(outcome), outcome, NULL),
            `if`( ! missing(predictors), predictors, NULL),
            `if`( ! missing(centerVariable), centerVariable, NULL),
            `if`( ! missing(elapsedtime), elapsedtime, NULL))

    for (v in centerVariable) if (v %in% names(data)) data[[v]] <- as.factor(data[[v]])

    options <- leaveonecenteroutOptions$new(
        outcome = outcome,
        outcomeLevel = outcomeLevel,
        predictors = predictors,
        centerVariable = centerVariable,
        elapsedtime = elapsedtime,
        modelType = modelType,
        useLasso = useLasso,
        lambdaMethod = lambdaMethod,
        random_seed = random_seed,
        pooledPerformance = pooledPerformance,
        forestPlot = forestPlot,
        calibrationCheck = calibrationCheck)

    analysis <- leaveonecenteroutClass$new(
        options = options,
        data = data)

    analysis$run()

    analysis$results
}

